   178	func (r migrationRunner) execute(ctx context.Context, migrations []Migration, limit int) (int, error) {
   179		currentVersion, dirty, err := r.getVersion(ctx)
   180		if err != nil {
   181			return 0, err
   182		}
   183	
   184		if dirty {
   185			return 0, fmt.Errorf("database is dirty at version %d; fix the issue and use 'migrate set' to reset the dirty flag", currentVersion)
   186		}
   187	
   188		applied := 0
   189		for _, m := range migrations {
   190			if m.Version <= currentVersion {
   191				continue
   192			}
   193			if limit > 0 && applied >= limit {
   194				break
   195			}
   196	
   197			// Set dirty flag.
   198			if err := r.setVersion(ctx, m.Version, true); err != nil {
   199				return applied, fmt.Errorf("setting dirty flag for version %d: %w", m.Version, err)
   200			}
   201	
   202			// Execute statements.
   203			switch m.Kind {
   204			case sqlutil.KindDDL:
   205				if err := r.updateDatabaseDDL(ctx, m.Statements); err != nil {
   206					return applied, fmt.Errorf("executing DDL migration %d (%s): %w", m.Version, m.Name, err)
   207				}
   208			case sqlutil.KindDML:
   209				if err := r.applyDML(ctx, m.Statements); err != nil {
   210					return applied, fmt.Errorf("executing DML migration %d (%s): %w", m.Version, m.Name, err)
   211				}
   212			case sqlutil.KindPartitionedDML:
   213				for _, stmt := range m.Statements {
   214					if _, err := r.applyPartitionedDML(ctx, stmt); err != nil {
   215						return applied, fmt.Errorf("executing partitioned DML migration %d (%s): %w", m.Version, m.Name, err)
   216					}
   217				}
   218			default:
   219				return applied, fmt.Errorf("unsupported migration kind %s for version %d (%s)", m.Kind, m.Version, m.Name)
   220			}
   221	
   222			// Clear dirty flag.
   223			if err := r.setVersion(ctx, m.Version, false); err != nil {
   224				return applied, fmt.Errorf("clearing dirty flag for version %d: %w", m.Version, err)
   225			}
   226	
   227			applied++
   228		}
   229	
   230		return applied, nil
   231	}
