   233	// isTableNotFoundError checks if the error indicates a table was not found.
   234	func isTableNotFoundError(err error) bool {
   235		if err == nil {
   236			return false
   237		}
   238		// Spanner returns INVALID_ARGUMENT when querying a non-existent table.
   239		return spanner.ErrCode(err) == codes.InvalidArgument
   240	}

