   121	func (r *recordingRunner) migrationRunner() migrationRunner {
   122		return migrationRunner{
   123			getVersion: func(context.Context) (uint, bool, error) {
   124				return r.currentVersion, r.dirty, r.getVersionErr
   125			},
   126			setVersion: func(_ context.Context, version uint, dirty bool) error {
   127				r.operations = append(r.operations, runnerOperation{
   128					Kind:    "setVersion",
   129					Version: version,
   130					Dirty:   dirty,
   131				})
   132				if r.setVersionErr == nil {
   133					return nil
   134				}
   135				return r.setVersionErr[versionDirtyKey(version, dirty)]
   136			},
   137			updateDatabaseDDL: func(_ context.Context, statements []string) error {
   138				r.operations = append(r.operations, runnerOperation{
   139					Kind:       "ddl",
   140					Statements: append([]string(nil), statements...),
   141				})
   142				return r.ddlErr
   143			},
   144			applyDML: func(_ context.Context, statements []string) error {
   145				r.operations = append(r.operations, runnerOperation{
   146					Kind:       "dml",
   147					Statements: append([]string(nil), statements...),
   148				})
   149				return r.dmlErr
   150			},
   151			applyPartitionedDML: func(_ context.Context, statement string) (int64, error) {
   152				r.operations = append(r.operations, runnerOperation{
   153					Kind:      "partitionedDML",
   154					Statement: statement,
   155				})
   156				if r.partitionErr == nil {
   157					return 1, nil
   158				}
   159				return 0, r.partitionErr[statement]
   160			},
   161		}
   162	}
