import (
	"strings"

	pluralize "github.com/gertd/go-pluralize"
)

var defaultPluralizer = pluralize.NewClient()

var commonInitialisms = map[string]struct{}{
	"ACL":   {},
	"API":   {},
	"ASCII": {},
	"CPU":   {},
	"CSS":   {},
	"DB":    {},
	"DDL":   {},
	"DML":   {},
	"DNS":   {},
	"EOF":   {},
	"GCP":   {},
	"GUID":  {},
	"HTML":  {},
	"HTTP":  {},
